function validateComposeFile(composeFile) {
  const lines = composeFile.split('\n');
  const portMappings = {};
  for (const line of lines) {
    if (line.startsWith('ports:')) {
      const service = line.split(':')[1].trim();
      const ports = line.split(':')[2].split(',').map(port => port.trim());
      for (const port of ports) {
        const [hostPort, containerPort] = port.split(':');
        if (portMappings[service] && portMappings[service].includes(hostPort)) {
          return false;
        }
        if (isNaN(parseInt(hostPort)) || isNaN(parseInt(containerPort))) {
          return false;
        }
        if (parseInt(hostPort) < 1 || parseInt(hostPort) > 65535 || parseInt(containerPort) < 1 || parseInt(containerPort) > 65535) {
          return false;
        }
        portMappings[service].push(hostPort);
      }
    }
  }
  return true;
}

