class Solution:
  def validate_compose_file(self, compose_file: str) -> bool:
    lines = compose_file.split('\n')
    port_mappings = {}
    for line in lines:
      if line.startswith('ports:'):
        service = line.split(':')[1].strip()
        ports = line.split(':')[2].split(',')
        for port in ports:
          host_port, container_port = port.split(':')
          if service in port_mappings and host_port in port_mappings[service]:
            return False
          if not host_port.isdigit() or not container_port.isdigit():
            return False
          if int(host_port) < 1 or int(host_port) > 65535 or int(container_port) < 1 or int(container_port) > 65535:
            return False
          port_mappings[service].append(host_port)
    return True
